import React, { useEffect, useState } from "react";
import { Link, useNavigate } from "react-router-dom";

function Navbar() {
  let [loggedUser, setLoggedUser] = useState(null);
  let navigate = useNavigate();

  useEffect(() => {
    function updateUser() {
      let user = localStorage.getItem("loggedUser");
      setLoggedUser(user ? JSON.parse(user) : null);
    }

    updateUser();
    window.addEventListener("authChanged", updateUser);

    return () => {
      window.removeEventListener("authChanged", updateUser);
    };
  }, []);

  function handleLogout() {
    localStorage.removeItem("loggedUser");
    setLoggedUser(null);
    window.dispatchEvent(new Event("authChanged"));
    navigate("/");
  }

  return (
    <header className="navbar">
      <div className="container navbar-content">
        <Link to="/" className="logo">
          Culinary Book
        </Link>

        <nav className="nav-links">
          <Link to="/">Strona główna</Link>
          <Link to="/przepisy">Przepisy</Link>

          {!loggedUser ? (
            <>
              <Link to="/logowanie">Logowanie</Link>
              <Link to="/rejestracja" className="register-button">
                Zarejestruj się
              </Link>
            </>
          ) : (
            <div className="user-nav-box">
              <div className="user-avatar">
                {loggedUser.nazwa_uzytkownika?.charAt(0)?.toUpperCase() || "U"}
              </div>
              <span className="user-name">{loggedUser.nazwa_uzytkownika}</span>
              <button className="logout-button" onClick={handleLogout}>
                Wyloguj
              </button>
            </div>
          )}
        </nav>
      </div>
    </header>
  );
}

export default Navbar;
